class SecurePaymentGateway implements PaymentGateway {
  final PaymentConfig config;
  final HttpClientAdapter httpClient;

  SecurePaymentGateway({
    required this.config,
    HttpClientAdapter? httpClient,
  }) : httpClient = httpClient ?? const HttpClientAdapter();

  @override
  Future<PaymentResult> charge(PaymentRequest request) async {
    if (!config.enableCardGateway) {
      return const PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: 'Card gateway disabled',
      );
    }
    final payload = <String, dynamic>{
      'referenceId': request.referenceId,
      'amount': request.amount,
      'currency': request.currency,
      'customerId': request.customerId,
      'metadata': request.metadata,
      'merchantId': config.gatewayMerchantId,
      'sandbox': config.sandbox,
    };
    final response = await httpClient.postJson(
      uri: Uri.parse('${config.backendReceiptValidationUrl ?? ''}/charge'),
      headers: _secureHeaders(),
      body: payload,
    );
    return _mapResponse(response);
  }

  @override
  Future<PaymentResult> validateReceipt({
    required String receiptData,
    required String productId,
    required String platform,
  }) async {
    final response = await httpClient.postJson(
      uri: Uri.parse('${config.backendReceiptValidationUrl ?? ''}/validate-receipt'),
      headers: _secureHeaders(),
      body: <String, dynamic>{
        'receiptData': receiptData,
        'productId': productId,
        'platform': platform,
        'sandbox': config.sandbox,
      },
    );
    return _mapResponse(response);
  }

  @override
  Future<PaymentResult> walletPay(PaymentRequest request) async {
    if (!config.enableMobileWallet) {
      return const PaymentResult(
        success: false,
        status: PaymentStatus.failed,
        message: 'Mobile wallet disabled',
      );
    }
    final response = await httpClient.postJson(
      uri: Uri.parse('${config.backendReceiptValidationUrl ?? ''}/wallet-pay'),
      headers: _secureHeaders(),
      body: <String, dynamic>{
        'referenceId': request.referenceId,
        'amount': request.amount,
        'currency': request.currency,
        'customerId': request.customerId,
        'metadata': request.metadata,
        'sandbox': config.sandbox,
      },
    );
    return _mapResponse(response);
  }

  Map<String, String> _secureHeaders() => <String, String>{
        'Content-Type': 'application/json',
        if (config.gatewayPublicKey != null) 'X-Public-Key': config.gatewayPublicKey!,
        'X-Client-App': config.appName,
      };

  PaymentResult _mapResponse(HttpResponseAdapter response) {
    final body = response.body;
    final data = body.isNotEmpty ? jsonDecode(body) as Map<String, dynamic> : <String, dynamic>{};
    final success = response.statusCode >= 200 && response.statusCode < 300 && data['success'] != false;
    return PaymentResult(
      success: success,
      status: success ? PaymentStatus.success : PaymentStatus.failed,
      transactionId: data['transactionId']?.toString(),
      message: data['message']?.toString(),
      raw: data,
    );
  }
}

