        case PaymentMethodType.inAppPurchase:
          return await _payWithIap(request);
        case PaymentMethodType.mobileWallet:
          return await gateway.walletPay(request);
        case PaymentMethodType.cardGateway:
          return await gateway.charge(request);
      }
    } catch (e) {
      _setStatus(PaymentStatus.failed, e.toString());
